import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { FaCamera, FaShareSquare, FaPencilAlt, FaHeart } from 'react-icons/fa';
import { Link } from 'react-router-dom';
import axios from 'axios';

const Profile = () => {
  const { user, updateUser } = useAuth();
  const [uploading, setUploading] = useState(false);

  // Hàm xử lý khi chọn ảnh
  const handleAvatarChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('avatar', file);

    setUploading(true);
    try {
      const res = await axios.put(`http://localhost:5000/api/users/${user._id}`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          'token': `Bearer ${user.token}`
        }
      });
      // Cập nhật lại context để hiển thị ảnh mới ngay lập tức
      updateUser(res.data);
      setUploading(false);
    } catch (err) {
      console.error(err);
      setUploading(false);
      alert("Update failed!");
    }
  };

  if (!user) return <div className="text-center mt-20">Please login to view profile.</div>;

  return (
    <div className="bg-gray-100 min-h-screen pb-24">
      {/* 1. Header Section (Gradient Background) */}
      <div className="relative h-64 bg-gradient-to-r from-gray-700 to-gray-900">
        <div className="absolute inset-0 bg-gradient-to-r from-orange-400/30 to-black/60"></div>
        
        <div className="max-w-7xl mx-auto px-6 h-full flex items-center relative">
            {/* Avatar Tròn to - Có chức năng Upload */}
            <div className="absolute bottom-[-40px] left-6 w-48 h-48 rounded-full border-4 border-white overflow-hidden bg-gray-300 shadow-lg group cursor-pointer relative">
                <img 
                    src={user.avatar || `https://ui-avatars.com/api/?name=${user.username}&background=random&size=200`} 
                    alt="avatar" 
                    className="w-full h-full object-cover"
                />
                {/* Lớp phủ khi hover để bấm upload */}
                <label className="absolute inset-0 bg-black/40 hidden group-hover:flex flex-col items-center justify-center text-white transition cursor-pointer">
                    <FaCamera className="text-2xl mb-1" />
                    <span className="text-sm">{uploading ? 'Uploading...' : 'Update image'}</span>
                    <input type="file" className="hidden" onChange={handleAvatarChange} accept="image/*" />
                </label>
            </div>

            {/* User Info - Đã sửa: Dòng dưới hiển thị Username thay vì Email */}
            <div className="ml-56 mb-8 text-white z-10">
                <h2 className="text-2xl font-bold bg-black/50 px-2 py-1 inline-block mb-1">{user.username}</h2>
                <p className="text-sm bg-black/50 px-2 py-1 inline-block text-gray-300 block w-fit">{user.username}</p>
            </div>

            {/* Upload Header Button */}
            <button className="absolute top-6 right-6 bg-black/30 hover:bg-black/50 text-white px-3 py-1.5 rounded text-sm flex items-center gap-2 border border-white/20 transition">
                <FaCamera /> Upload header image
            </button>
        </div>
      </div>

      {/* 2. Navigation & Actions Bar */}
      <div className="bg-white border-b border-gray-200 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 pl-60 py-3 flex justify-between items-center h-16">
            {/* Tabs */}
            <div className="flex gap-6 text-sm font-semibold text-gray-600">
                <button className="text-orange-500 border-b-2 border-orange-500 pb-4 -mb-4">All</button>
                <button className="hover:text-black transition">Popular tracks</button>
                <button className="hover:text-black transition">Tracks</button>
                <button className="hover:text-black transition">Albums</button>
                <button className="hover:text-black transition">Playlists</button>
                <button className="hover:text-black transition">Reposts</button>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-2">
                <button className="flex items-center gap-2 px-3 py-1 border border-gray-300 rounded text-sm hover:border-gray-400 transition">
                    <FaShareSquare /> Share
                </button>
                <button className="flex items-center gap-2 px-3 py-1 border border-gray-300 rounded text-sm hover:border-gray-400 transition">
                    <FaPencilAlt /> Edit
                </button>
            </div>
        </div>
      </div>

      {/* 3. Main Content (2 Columns) */}
      <div className="max-w-7xl mx-auto px-6 mt-8 grid grid-cols-1 lg:grid-cols-4 gap-8">
        
        {/* Left Column: Tracks List (Empty State) */}
        <div className="lg:col-span-3">
            <div className="text-center py-16 border-2 border-dashed border-gray-300 rounded-lg bg-white">
                <h3 className="text-lg font-bold text-gray-700 mb-2">Seems a little quiet over here</h3>
                <p className="text-gray-500 text-sm mb-6">Upload a track to share it with your followers.</p>
                <Link to="/upload" className="bg-orange-500 text-white px-4 py-2 rounded font-bold hover:bg-orange-600 transition">
                    Upload now
                </Link>
            </div>
        </div>

        {/* Right Column: Stats Sidebar */}
        <div className="lg:col-span-1 space-y-6">
            {/* Stats */}
            <div className="flex justify-between text-gray-500 text-xs border-b pb-4">
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">Followers</div>
                    <div className="text-xl font-bold text-gray-700">0</div>
                </div>
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">Following</div>
                    <div className="text-xl font-bold text-gray-700">0</div>
                </div>
                <div className="cursor-pointer hover:text-orange-500">
                    <div className="text-gray-400 uppercase mb-1">Tracks</div>
                    <div className="text-xl font-bold text-gray-700">0</div>
                </div>
            </div>

            {/* Likes Preview */}
            <div>
                <div className="flex justify-between items-end mb-3">
                    <span className="text-gray-500 text-xs font-bold uppercase flex items-center gap-1">
                        0 Likes <FaHeart className="text-gray-400" />
                    </span>
                    <span className="text-xs text-gray-400 hover:text-gray-600 cursor-pointer">View all</span>
                </div>
                <div className="grid grid-cols-3 gap-2">
                    {/* Fake Likes Placeholder */}
                    <div className="aspect-square bg-gray-200 rounded"></div>
                    <div className="aspect-square bg-gray-200 rounded"></div>
                    <div className="aspect-square bg-gray-200 rounded"></div>
                </div>
            </div>
            
            {/* Footer Links Mini */}
            <div className="text-[10px] text-gray-400 pt-4 border-t">
                Legal • Privacy • Cookies • Imprint • Creator Resources • Blog • Charts
            </div>
        </div>

      </div>
    </div>
  );
};

export default Profile;
